INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 1, "2030/01/01 14:59:59", -416.5, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 3.414, 190801, "2025/01/31 12:00:00", 1000001, 1, 62, 2, 0.0, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 2, "2030/01/01 14:59:59", -416.5, "ミッションをクリアして、\n報酬をゲットしましょう！", 3.099, 190801, "2025/01/31 12:00:00", 1000002, 1, 62, 2, 0.0, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 3, "2030/01/01 14:59:59", -416.5, "受け取ることができる\n報酬があるようです\n確認してみてください", 2.801, 190801, "2025/01/31 12:00:00", 1000003, 1, 63, 2, 0.0, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 4, "2030/01/01 14:59:59", -416.5, "報酬がもらえますよ！\nチェックしてみてください", 0.0, 190801, "2025/01/31 12:00:00", 1000004, 2, 63, 2, 0.0, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 5, "2030/01/01 14:59:59", -363.0, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 2.12, 190801, "2025/01/31 12:00:00", 1000005, 2, 64, 1, 0.0, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 6, "2030/01/01 14:59:59", -363.0, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 1.68, 190801, "2025/01/31 12:00:00", 1000006, 1, 64, 2, 0.0, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 7, "2030/01/01 14:59:59", -363.0, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 2.33, 190801, "2025/01/31 12:00:00", 1000007, 2, 64, 1, 0.0, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10201, 101, "2030/01/01 14:59:59", -285.0, "今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を", 5.18, 133701, "2025/01/31 12:00:00", 1020101, 3, 61, 7, -6.0, "ラビリスタ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10201, 201, "2030/01/01 14:59:59", -285.0, "退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな", 8.77, 133901, "2025/01/31 12:00:00", 1020102, 1, 61, 2, -2.0, "クリスティーナ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10201, 301, "2030/01/01 14:59:59", -285.0, "おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます", 15.5, 133801, "2025/01/31 12:00:00", 1020103, 6, 61, 1, 0.0, "ネネカ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10202, 101, "2030/01/01 14:59:59", -285.0, "わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…", 9.061, 134301, "2025/02/28 12:00:00", 1020201, 2, 61, 5, 0.0, "ランファ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10202, 201, "2030/01/01 14:59:59", -285.0, "同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ", 7.699, 134401, "2025/02/28 12:00:00", 1020202, 1, 61, 2, 0.0, "チカ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10203, 101, "2030/01/01 14:59:59", -285.0, "世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！", 8.595, 134601, "2025/03/31 12:00:00", 1020301, 1, 61, 2, 0.0, "アオイ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10203, 201, "2030/01/01 14:59:59", -285.0, "新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ", 7.758, 134501, "2025/03/31 12:00:00", 1020302, 1, 61, 2, 0.0, "クローチェ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10204, 101, "2030/01/01 14:59:59", -285.0, "今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！", 7.0, 132302, "2025/04/30 12:00:00", 1020401, 2, 61, 6, 0.0, "ルイズマリー");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10204, 201, "2030/01/01 14:59:59", -285.0, "ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪", 7.904, 132402, "2025/04/30 12:00:00", 1020402, 1, 61, 2, 0.0, "イロハ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10204, 301, "2030/01/01 14:59:59", -285.0, "ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～", 8.487, 132502, "2025/04/30 12:00:00", 1020403, 4, 61, 2, 0.0, "ソノ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10205, 101, "2030/01/01 14:59:59", -285.0, "ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪", 8.763, 134901, "2025/05/31 12:00:00", 1020502, 1, 61, 2, 0.0, "カノン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10205, 201, "2030/01/01 14:59:59", -285.0, "いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！", 6.417, 134801, "2025/05/31 12:00:00", 1020503, 1, 61, 3, 0.0, "ツムギ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10206, 101, "2030/01/01 14:59:59", -285.0, "『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる", 10.335, 135001, "2025/06/30 12:00:00", 1020601, 3, 61, 7, 0.0, "エリス");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10206, 201, "2030/01/01 14:59:59", -285.0, "せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？", 6.281, 135101, "2025/06/30 12:00:00", 1020602, 2, 61, 4, 0.0, "シェフィ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10206, 301, "2030/01/01 14:59:59", -285.0, "いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ", 12.244, 135201, "2025/06/30 12:00:00", 1020603, 1, 61, 2, 0.0, "プレシア");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10207, 101, "2030/01/01 14:59:59", -285.0, "ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…", 6.339, 135301, "2025/07/31 12:00:00", 1020701, 2, 61, 8, 0.0, "クリア");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10207, 201, "2030/01/01 14:59:59", -285.0, "─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです", 8.184, 135401, "2025/07/31 12:00:00", 1020702, 7, 61, 9, 0.0, "アネモネ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10208, 101, "2030/01/01 14:59:59", -285.0, "あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！", 3.906, 129101, "2025/08/31 12:00:00", 1020801, 9, 61, 2, 0.0, "アイラ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10208, 201, "2030/01/01 14:59:59", -285.0, "繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？", 14.465, 129201, "2025/08/31 12:00:00", 1020802, 1, 61, 2, 0.0, "シナツ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10208, 301, "2030/01/01 14:59:59", -285.0, "アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！", 8.662, 100101, "2025/08/31 12:00:00", 1020803, 4, 61, 3, 0.0, "ヒヨリ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10208, 401, "2030/01/01 14:59:59", -285.0, "シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！", 10.915, 100301, "2025/08/31 12:00:00", 1020804, 1, 61, 3, 0.0, "レイ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10209, 101, "2030/01/01 14:59:59", -285.0, "あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…", 6.042, 135802, "2025/09/30 12:00:00", 1020901, 1, 61, 7, 0.0, "ユキノ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10209, 201, "2030/01/01 14:59:59", -285.0, "なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公", 9.402, 135903, "2025/09/30 12:00:00", 1020902, 4, 61, 1, 0.0, "サツキ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10209, 301, "2030/01/01 14:59:59", -285.0, "う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい", 8.16, 136902, "2025/09/30 12:00:00", 1020903, 8, 61, 1, 0.0, "ルルィ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10210, 101, "2030/01/01 14:59:59", -285.0, "ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！", 5.0, 137401, "2025/10/31 12:00:00", 1021001, 3, 61, 2, 0.0, "カスミ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10210, 201, "2030/01/01 14:59:59", -285.0, "…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします", 8.12, 136001, "2025/10/31 12:00:00", 1021002, 4, 61, 1, 0.0, "アラクネ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10210, 301, "2030/01/01 14:59:59", -285.0, "ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！", 6.386, 136202, "2025/10/31 12:00:00", 1021003, 4, 61, 2, 0.0, "ナーナ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10211, 101, "2030/01/01 14:59:59", -285.0, "騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？", 7.438, 136402, "2025/11/30 12:00:00", 1021101, 3, 61, 4, 0.0, "ユイ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10211, 201, "2030/01/01 14:59:59", -285.0, "騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね", 8.35, 136302, "2025/11/30 12:00:00", 1021102, 1, 61, 5, 0.0, "ミソラ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10212, 101, "2030/01/01 14:59:59", -285.0, "新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！", 5.0, 136501, "2025/12/31 12:00:00", 1021201, 1, 61, 2, 0.0, "シズル");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10212, 201, "2030/01/01 14:59:59", -285.0, "おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！", 5.25, 137902, "2025/12/31 12:00:00", 1021202, 1, 61, 2, 0.0, "リノ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10212, 301, "2030/01/01 14:59:59", -285.0, "年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！", 7.5, 106801, "2025/12/31 12:00:00", 1021203, 1, 61, 2, 0.0, "ラビリスタ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10213, 101, "2030/01/01 14:59:59", -285.0, "漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪", 8.204, 126501, "2026/01/31 12:00:00", 1021301, 1, 61, 2, 0.0, "ライラエル");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10213, 201, "2030/01/01 14:59:59", -285.0, "異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする", 7.176, 129701, "2026/01/31 12:00:00", 1021302, 1, 61, 2, 0.0, "ネフィ＝ネラ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10213, 301, "2030/01/01 14:59:59", -285.0, "『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！", 8.602, 133101, "2026/01/31 12:00:00", 1021303, 1, 61, 5, 0.0, "ヴァイオレット");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10213, 102, "2030/01/01 14:59:59", -285.0, "多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？", 10.14, 138101, "2026/02/06 12:00:00", 1021304, 1, 61, 3, 0.0, "ライラエル");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10213, 202, "2030/01/01 14:59:59", -285.0, "煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん", 10.152, 138201, "2026/02/06 12:00:00", 1021305, 1, 61, 7, 0.0, "ネフィ＝ネラ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10213, 302, "2030/01/01 14:59:59", -285.0, "裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！", 9.688, 138001, "2026/02/06 12:00:00", 1021306, 4, 61, 3, 0.0, "ヴァイオレット");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10213, 401, "2030/01/01 14:59:59", -285.0, "みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！", 5.928, 138301, "2026/02/12 12:00:00", 1021307, 2, 61, 1, 0.0, "ペコリーヌ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10214, 101, "2030/01/01 14:59:59", -285.0, "成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？", 9.19, 138702, "2026/02/28 12:00:00", 1021401, 4, 61, 2, 0.0, "ワカナ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10214, 201, "2030/01/01 14:59:59", -285.0, "「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！", 8.724, 138802, "2026/02/28 12:00:00", 1021402, 1, 61, 3, 0.0, "シオリ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10215, 101, "2030/01/01 14:59:59", -285.0, "私がへんたいふしんしゃさんって…\nただ生きているだけなのに、ひどい\n…まぁ死んでるんですけど…とか\n言ってる暇もない感じですか？", 7.758, 138902, "2026/03/31 12:00:00", 1021501, 4, 61, 1, 0.0, "グレイス");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10215, 201, "2030/01/01 14:59:59", -285.0, "あの、助けてください！\n私がへんたいふしんしゃさんに\nなっちゃったみたいなんです…！\nどういう意味かは私もわかりません", 6.375, 139002, "2026/03/31 12:00:00", 1021502, 6, 61, 4, 0.0, "キョウカ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10215, 301, "2030/01/01 14:59:59", -285.0, "ましゃか、グレイス姉しゃまたちが\nへんたいふしんしゃさんだなんて…\n騎士しゃん。あたちたちも協力ちて\n二人の破滅エンドを回避ちましょう", 6.173, 136902, "2026/03/31 12:00:00", 1021503, 6, 61, 1, 0.0, "ルルィ");
